class Solution:
    def maximumTotalCost(self, nums: List[int]) -> int:
        n = len(nums)
        if n == 1:
            return nums[0]

        # dp[i] represents the maximum total cost for the first i elements
        dp = [0] * (n + 1)

        # Initialize dp[0] = 0 (no elements), dp[1] = cost of first element
        dp[1] = nums[0]

        for i in range(2, n + 1):
            # Option 1: Do not split, take the cost of the entire subarray from 0 to i-1
            cost_no_split = 0
            for j in range(i):
                cost_no_split += nums[j] * ((-1) ** (j - 0))
            # Option 2: Split at some position k < i-1, take max(dp[k] + cost(k, i-1))
            max_split = 0
            for k in range(1, i):
                cost_split = 0
                for j in range(k, i):
                    cost_split += nums[j] * ((-1) ** (j - k))
                max_split = max(max_split, dp[k] + cost_split)
            dp[i] = max(dp[i], cost_no_split, max_split)

        return dp[n]
